#include <bits/stdc++.h>
using namespace std;
int n,k,a[21],ans,sum;
bool is_prime(int x){
    if(x<2)
        return false;
    for(int i=2;i*i<=x;i++)
        if(x%i==0)
            return false;
    return true;
}
void dfs(int x,int last){
    if(x>k){
        ans+=is_prime(sum);
        return;
    }
    for(int i=last+1;i<=n-(k-x);i++)
        sum+=a[i],dfs(x+1,i),sum-=a[i];
}
int main(){
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    dfs(1,0);
    printf("%d",ans);
    return 0;
}
